from fastapi import HTTPException, status


class ApiError(HTTPException):
    def __init__(self, status_code: int, code: str, message: str, details: dict | None = None):
        super().__init__(status_code=status_code, detail={"code": code, "message": message, "details": details or {}})


def unauthorized(message: str = "Authentication failed") -> ApiError:
    return ApiError(status_code=status.HTTP_401_UNAUTHORIZED, code="AUTHENTICATION_FAILED", message=message)


def forbidden(message: str = "Forbidden") -> ApiError:
    return ApiError(status_code=status.HTTP_403_FORBIDDEN, code="FORBIDDEN", message=message)


def conflict(code: str, message: str, details: dict | None = None) -> ApiError:
    return ApiError(status_code=status.HTTP_409_CONFLICT, code=code, message=message, details=details)


def validation_error(message: str, details: dict | None = None) -> ApiError:
    return ApiError(status_code=status.HTTP_400_BAD_REQUEST, code="VALIDATION_ERROR", message=message, details=details)

import os
import secrets
from datetime import datetime, timedelta, timezone

from passlib.context import CryptContext

from app.core.config import settings

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")


def generate_salt() -> str:
    return secrets.token_hex(16)


def hash_password(password: str, salt: str) -> str:
    return pwd_context.hash(f"{salt}:{password}")


def verify_password(password: str, salt: str, password_hash: str) -> bool:
    return pwd_context.verify(f"{salt}:{password}", password_hash)


def utc_now() -> datetime:
    return datetime.now(timezone.utc)


def is_locked(locked_until: datetime | None) -> bool:
    if locked_until is None:
        return False
    return locked_until > utc_now()


def should_reset_failed_window(first_failed_login_at: datetime | None) -> bool:
    if first_failed_login_at is None:
        return True
    return first_failed_login_at + timedelta(minutes=settings.login_window_minutes) < utc_now()


def lock_until_time() -> datetime:
    return utc_now() + timedelta(minutes=settings.login_lock_minutes)

from datetime import datetime, timedelta, timezone

import jwt

from app.core.config import settings


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def create_access_token(subject: str, role: str) -> str:
    now = _utcnow()
    payload = {
        "sub": subject,
        "role": role,
        "type": "access",
        "iat": int(now.timestamp()),
        "exp": int((now + timedelta(minutes=settings.jwt_access_exp_minutes)).timestamp()),
    }
    return jwt.encode(payload, settings.jwt_access_secret, algorithm="HS256")


def create_refresh_token(subject: str, role: str) -> str:
    now = _utcnow()
    payload = {
        "sub": subject,
        "role": role,
        "type": "refresh",
        "iat": int(now.timestamp()),
        "exp": int((now + timedelta(minutes=settings.jwt_refresh_exp_minutes)).timestamp()),
    }
    return jwt.encode(payload, settings.jwt_refresh_secret, algorithm="HS256")


def decode_access_token(token: str) -> dict:
    return jwt.decode(token, settings.jwt_access_secret, algorithms=["HS256"])


def decode_refresh_token(token: str) -> dict:
    return jwt.decode(token, settings.jwt_refresh_secret, algorithms=["HS256"])

import uuid

from fastapi import Depends, Header, Request
from sqlalchemy.orm import Session

from app.core.database import get_db


def db_session() -> Session:
    return Depends(get_db)


def get_request_id(x_request_id: str | None = Header(default=None)) -> str:
    return x_request_id or f"req_{uuid.uuid4().hex}"


def get_client_ip(request: Request) -> str | None:
